insert into public.messages (id, trip_id, sender_member_id, guest_name, body, thread_date, is_announcement, is_deleted) values ('b93e72a2-f0a5-542f-86f9-8f82e3e7760d', '0039b7b6-fa06-5288-8ab8-bd612320d7f5', 'a1b2c3d4-0001-0001-0001-000000000001', null, 'Tee times are locked in for both days! 🎉 Pebble on Friday at 7:10am and Spyglass on Saturday at 8:30am. Make sure you''re at the starter shack 30 minutes early.', '2025-05-20', true, false) on conflict (id) do nothing;
